141	  it("should reimburse at 50% for items with enchantment >= 8", () => {
142	    const policyItems = [{ type: "sword", material: "steel", enchantment: 9, cursed: false }];
143	    const damages = [{ itemType: "sword", amount: 1000 }];
144	    const result = claim(policyItems, damages);
145	    expect(result.payout).toBe(400);
146	    expect(result.remainingCap).toBe(1600);
147	  });
148	  it("should fully reimburse dragon material items", () => {
149	    const policyItems = [{ type: "sword", material: "dragon", enchantment: 5, cursed: false }];
150	    const damages = [{ itemType: "sword", amount: 800 }];
151	    const result = claim(policyItems, damages);
152	    expect(result.payout).toBe(700);
153	    expect(result.remainingCap).toBe(1300);
154	  });
155	  it("should apply 50% rule when item has both enchantment >= 8 and dragon material", () => {
156	    const policyItems = [{ type: "sword", material: "dragon", enchantment: 9, cursed: false }];
157	    const damages = [{ itemType: "sword", amount: 1000 }];
158	    const result = claim(policyItems, damages);
159	    expect(result.payout).toBe(400);
160	    expect(result.remainingCap).toBe(1600);
161	  });
162	  it("should round down the payout in MHPCO's favor", () => {
