1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const PROCESSING_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  potion: 40,
11	  amulet: 60,
12	  staff: 80,
13	  rune: 25,
14	};
15	
16	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
17	
18	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
19	
20	const COMPONENT_PREMIUM = 25;
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PREMIUM = 60;
23	
24	const isComponentBlock = (group: Item[]): boolean =>
25	  group.length === COMPONENT_BLOCK_SIZE && itemBasePremium(group[0]) === COMPONENT_PREMIUM;
26	
27	const groupPremium = (group: Item[]): number =>
28	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : group.reduce((sum, item) => sum + itemBasePremium(item), 0);
29	
30	const groupItemsByType = (items: Item[]): Map<string, Item[]> => {
31	  const groups = new Map<string, Item[]>();
32	  for (const item of items) {
33	    const group = groups.get(item.type) ?? [];
34	    group.push(item);
35	    groups.set(item.type, group);
36	  }
37	  return groups;
38	};
39	
40	const totalBasePremium = (items: Item[]): number =>
41	  Array.from(groupItemsByType(items).values()).reduce(
42	    (total, group) => total + groupPremium(group),
43	    0
44	  );
45	
46	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
47	  items.filter(appliesTo).reduce((sum, item) => sum + itemBasePremium(item) * rate, 0);
48	
49	const conditionalDiscount = (applies: boolean, amount: number, rate: number): number =>
50	  applies ? amount * rate : 0;
51	
52	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
53	  const basePremium = totalBasePremium(items);
54	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
55	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
56	  const itemTotal = basePremium + cursedSurcharge + enchantmentSurcharge;
57	
58	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
59	  const followUpDiscount = conditionalDiscount(contractIndex > 0, basePremium, FOLLOW_UP_DISCOUNT_RATE);
60	  const loyaltyDiscount = conditionalDiscount(customer.yearsWithMHPCO >= 2, basePremium, LOYALTY_DISCOUNT_RATE);
61	  const policyAdjustment = firstInsuranceSurcharge - followUpDiscount - loyaltyDiscount;
62	
63	  return Math.ceil(itemTotal + policyAdjustment + PROCESSING_FEE);
64	}
65	
66	const INSURANCE_VALUE: Record<string, number> = {
67	  sword: 1000,
68	  amulet: 600,
69	  staff: 800,
70	  potion: 400,
71	  rune: 250,
72	};
73	
74	const DEDUCTIBLE = 100;
75	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
76	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
77	
78	const isHighEnchantmentClaim = (policyItem: Item | undefined): boolean =>
79	  policyItem !== undefined && policyItem.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
80	
81	const reimbursableAmount = (damage: { amount: number }, policyItem: Item | undefined): number =>
82	  isHighEnchantmentClaim(policyItem)
83	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
84	    : damage.amount;
85	
86	const claimableAmount = (damage: { itemType: string; amount: number }, policyItems: Item[]): number => {
87	  const policyItem = policyItems.find((item) => item.type === damage.itemType);
88	  return Math.max(0, reimbursableAmount(damage, policyItem) - DEDUCTIBLE);
89	};
90	
91	export function claim(policyItems: Item[], damages: Array<{ itemType: string; amount: number }>) {
92	  const insuranceSum = policyItems.reduce((sum, item) => sum + (INSURANCE_VALUE[item.type] ?? 0), 0);
93	  const payoutCap = 2 * insuranceSum;
94	  const uncappedPayout = damages.reduce((sum, damage) => sum + claimableAmount(damage, policyItems), 0);
95	  const payout = Math.floor(Math.min(uncappedPayout, payoutCap));
96	  return { payout, remainingCap: payoutCap - payout };
97	}
